parameters.jsCode:
// Deadline engine (Luxon). Computes the limitation period and any procedural
// deadlines for one matter, recording the rule applied. DateTime is the Luxon
// global provided by n8n. Edit the rules in the "Set the Rules Table" node, not here.

const form = $('Receive Matter Intake Form').first().json;
const cfg = $('Set the Rules Table').first().json;

function asObj(v) { return typeof v === 'string' ? JSON.parse(v) : v; }
function asNums(v) {
  if (Array.isArray(v)) return v.map(Number);
  return String(v).split(',').map(s => Number(s.trim())).filter(n => !isNaN(n));
}

const limitationRules = asObj(cfg.limitationRules);
const proceduralRules = asObj(cfg.proceduralRules);
const holidays = asObj(cfg.holidays);
const reminderOffsets = asNums(cfg.reminderOffsets);
const rollDeadlines = cfg.rollDeadlinesToBusinessDay === true || cfg.rollDeadlinesToBusinessDay === 'true';
const rollReminders = cfg.rollRemindersBackToBusinessDay === true || cfg.rollRemindersBackToBusinessDay === 'true';
const timezone = cfg.timezone || 'America/Toronto';

const input = {
  matterName: form['Matter name or file number'],
  clientName: form['Client name'] || '',
  jurisdiction: form['Jurisdiction'],
  claimType: form['Claim type'],
  triggerEventType: form['Trigger event type'],
  triggerEventDate: form['Trigger event date'],
  serviceDate: form['Date claim issued or served'] || '',
  responsibleEmail: form['Responsible lawyer email'] || '',
  notes: form['Notes'] || '',
};

const now = DateTime.now().setZone(timezone);
const DISCLAIMER = 'Scheduling aid only, not legal advice. Verify against the current statute and rules of court.';

// Anchors a limitation period may validly be measured from. Every rule is discovery-
// basis; the date of loss/act is a conservative proxy (on or before discovery). A
// service or filing date falls after discovery, so a limitation measured from it would
// overstate the time remaining; those anchors drive procedural deadlines only.
const LIMITATION_ANCHORS = ['Date of discovery', 'Date of loss / act or omission'];

// Highest year the holiday list covers, to flag deadlines that land beyond it.
const maxHolidayYear = holidays.reduce(function (max, d) {
  const y = Number(String(d).slice(0, 4));
  return (isFinite(y) && y > max) ? y : max;
}, 0);

function isNonWorkingDay(dt) {
  if (dt.weekday === 6 || dt.weekday === 7) return true;
  return holidays.includes(dt.toISODate());
}
function rollForward(dt) { let d = dt; while (isNonWorkingDay(d)) d = d.plus({ days: 1 }); return d; }
function rollBackward(dt) { let d = dt; while (isNonWorkingDay(d)) d = d.minus({ days: 1 }); return d; }
function buildReminders(deadlineDt) {
  const out = [];
  for (const offset of reminderOffsets) {
    let r = deadlineDt.minus({ days: offset });
    if (rollReminders) r = rollBackward(r);
    if (r.startOf('day') < now.startOf('day')) continue;
    out.push({ label: offset + 'd', date: r.toISODate() });
  }
  return out;
}

const jur = limitationRules[input.jurisdiction];
if (!jur) {
  throw new Error('No limitation rules found for jurisdiction "' + input.jurisdiction + '". Add it to the rules table. Available: ' + Object.keys(limitationRules).join(', ') + '.');
}
const rule = jur[input.claimType];
if (!rule) {
  throw new Error('No limitation rule for claim type "' + input.claimType + '" in ' + input.jurisdiction + '. Add it to the rules table. Available: ' + Object.keys(jur).join(', ') + '.');
}

const trigger = DateTime.fromISO(input.triggerEventDate, { zone: timezone });
if (!trigger.isValid) {
  throw new Error('Trigger event date "' + input.triggerEventDate + '" is not a valid date.');
}

const results = [];

function makeRecord(deadlineType, deadlineName, basis, fromDateLabel, citation) {
  return {
    matterName: input.matterName,
    clientName: input.clientName,
    jurisdiction: input.jurisdiction,
    claimType: input.claimType,
    deadlineType: deadlineType,
    deadlineName: deadlineName,
    ruleCitation: citation,
    basis: basis,
    fromDateLabel: fromDateLabel,
    computedDateRaw: null,
    computedDate: null,
    rolled: false,
    daysUntil: null,
    reminders: [],
    warning: '',
    responsibleEmail: input.responsibleEmail,
    notes: input.notes,
    disclaimer: DISCLAIMER,
  };
}

function pushDeadline(deadlineType, deadlineName, rawDt, basis, fromDateLabel, citation) {
  const adjusted = rollDeadlines ? rollForward(rawDt) : rawDt;
  const rec = makeRecord(deadlineType, deadlineName, basis, fromDateLabel, citation);
  rec.computedDateRaw = rawDt.toISODate();
  rec.computedDate = adjusted.toISODate();
  rec.rolled = adjusted.toISODate() !== rawDt.toISODate();
  rec.daysUntil = Math.round(adjusted.startOf('day').diff(now.startOf('day'), 'days').days);
  rec.reminders = buildReminders(adjusted);
  if (rollDeadlines && adjusted.year > maxHolidayYear) {
    rec.warning = 'Holiday roll covers through ' + maxHolidayYear + '; the ' + adjusted.year + ' date was rolled off weekends only. Extend the holiday list to cover ' + adjusted.year + ' for full accuracy.';
  }
  results.push(rec);
}

function pushNote(deadlineType, deadlineName, warning) {
  const rec = makeRecord(deadlineType, deadlineName, '', 'Trigger event (' + input.triggerEventType + ')', '');
  rec.warning = warning;
  results.push(rec);
}

// Basic limitation period, but only from an anchor it can validly run from. From a
// service or filing anchor we emit a review note instead of a date that would overstate
// the time remaining.
if (LIMITATION_ANCHORS.includes(input.triggerEventType)) {
  pushDeadline('Limitation', rule.years + '-year limitation period', trigger.plus({ years: rule.years }), rule.basis, 'Trigger event (' + input.triggerEventType + ')', rule.citation);
} else {
  pushNote('Limitation (review needed)', 'Limitation not calculated from this trigger type', 'Limitation not calculated: a "' + input.triggerEventType + '" date falls after discovery, so a limitation period measured from it would overstate the time remaining. If the action is not yet commenced, re-run using "Date of discovery" (or "Date of loss / act or omission" as a conservative fallback).');
}

if (rule.ultimateYears && input.triggerEventType === 'Date of loss / act or omission') {
  pushDeadline('Ultimate limitation', rule.ultimateYears + '-year ultimate limitation period', trigger.plus({ years: rule.ultimateYears }), 'Act or omission', 'Trigger event (' + input.triggerEventType + ')', rule.citation);
}

if (input.serviceDate) {
  const served = DateTime.fromISO(input.serviceDate, { zone: timezone });
  if (!served.isValid) {
    throw new Error('Date claim issued/served "' + input.serviceDate + '" is not a valid date.');
  }
  const procRules = proceduralRules[input.jurisdiction] || [];
  if (procRules.length === 0) {
    pushNote('Procedural (none configured)', 'No procedural rule configured for this jurisdiction', 'A claim issued/served date was provided but no procedural rule is configured for ' + input.jurisdiction + '. Verify any defence or response deadline manually, or add a rule to proceduralRules.');
  } else {
    for (const p of procRules) {
      pushDeadline('Procedural', p.name, served.plus({ days: p.days }), p.days + ' days from ' + p.fromEvent, 'Claim issued/served', p.citation);
    }
  }
}

return results.map(json => ({ json: json }));

