// Build one human-readable summary across all calculated deadlines for the matter.
// Dated deadlines show the due date and reminders; review notes (for example a
// limitation that could not be calculated from the chosen trigger anchor) show their
// warning, so nothing is dropped silently.
const rows = $('Calculate Matter Deadlines').all().map(i => i.json);
const cfg = $('Set the Rules Table').first().json;
if (rows.length === 0) return [];

const matter = rows[0].matterName;
const recipient = rows[0].responsibleEmail || cfg.fallbackNotifyEmail || '';
const channel = cfg.slackChannel || '';

const lines = rows.map(r => {
  if (!r.computedDate) {
    // Note row: no calendar date, surface the warning instead.
    return '- ' + r.deadlineType + ': ' + r.deadlineName + '\n    ' + r.warning;
  }
  const rollNote = r.rolled ? ' (statutory date ' + r.computedDateRaw + ' fell on a weekend or holiday, moved to the next business day)' : '';
  const rem = r.reminders.length ? r.reminders.map(x => x.label + ' before, on ' + x.date).join('; ') : 'none still upcoming';
  const warn = r.warning ? '\n    Note: ' + r.warning : '';
  return '- ' + r.deadlineType + ': ' + r.deadlineName +
    '\n    Due ' + r.computedDate + rollNote + ' (' + r.daysUntil + ' days out)' +
    '\n    Rule: ' + r.ruleCitation +
    '\n    Reminders: ' + rem + warn;
});

const dated = rows.filter(r => r.computedDate).length;
const summaryText = 'Calculated deadlines for ' + matter + ' (' + rows[0].jurisdiction + ', ' + rows[0].claimType + ')\n\n' +
  lines.join('\n\n') + '\n\n' + rows[0].disclaimer;
const subject = 'Litigation deadlines: ' + matter;

return [{ json: { matterName: matter, recipientEmail: recipient, slackChannel: channel, subject: subject, summaryText: summaryText, deadlineCount: dated, noteCount: rows.length - dated } }];
